-- FIX 2: CRC32 integrity check — yield-friendly (task.wait every 4 KB)
local function _0x3ad5c24f9cf5f8e7(t, expected)
    local crc  = 0xFFFFFFFF
    local BATCH = 4096
    for start = 1, #t, BATCH do
